// Sem @State — isso NÃO compila:
struct ContadorView: View {
    var contador = 0  // struct não pode mutar

    var body: some View {
        Button("\(contador)") {
            contador += 1  // ERRO: Cannot assign to property: 'self' is immutable
        }
    }
}

// Com @State — funciona corretamente:
struct ContadorView: View {
    @State private var contador = 0  // armazenado fora da struct

    var body: some View {
        Button("\(contador)") {
            contador += 1  // muta o armazenamento externo, View é recriada
        }
    }
}

// Correto — @State como estado interno privado:
struct FormularioView: View {
    @State private var nome = ""
    @State private var emailValido = false
    @State private var mostrarErro = false

    var body: some View {
        VStack {
            TextField("Nome", text: $nome)
            if mostrarErro {
                Text("Nome inválido").foregroundStyle(.red)
            }
            Button("Salvar") {
                mostrarErro = nome.count < 3
            }
        }
    }
}

// View pai — tem o @State:
struct AppView: View {
    @State private var mostrarModal = false

    var body: some View {
        VStack {
            BotaoAbrirModal(aberto: $mostrarModal)  // $ passa o Binding
            if mostrarModal {
                Text("Modal aberto!")
            }
        }
    }
}

// View filha — recebe @Binding:
struct BotaoAbrirModal: View {
    @Binding var aberto: Bool  // referência ao @State da pai

    var body: some View {
        Button("Abrir") {
            aberto = true  // escreve diretamente no @State da pai
        }
    }
}

// Para criar um Binding de teste em Preview:
#Preview {
    BotaoAbrirModal(aberto: .constant(false))  // .constant cria Binding fixo
}

// @Observable — forma moderna:
@Observable
class SessaoUsuario {
    var usuarioLogado: Usuario?  // @Observable rastreia automaticamente
    var tema: Tema = .claro
    var notificacoesAtivas = true

    func fazerLogin(email: String, senha: String) async throws {
        usuarioLogado = try await AuthService.login(email: email, senha: senha)
    }

    func fazerLogout() {
        usuarioLogado = nil
    }
}

// ObservableObject — forma legada (iOS 13-16), mais verbosa:
class SessaoUsuarioLegada: ObservableObject {
    @Published var usuarioLogado: Usuario?  // cada propriedade precisa de @Published
    @Published var tema: Tema = .claro
}

// A View raiz cria e é dona do objeto:
struct AppView: View {
    @State private var sessao = SessaoUsuario()  // @State pois View é dona

    var body: some View {
        ContentView()
            .environment(sessao)  // injeta para toda a hierarquia
    }
}

// View filha acessa via @Environment:
struct PerfilView: View {
    @Environment(SessaoUsuario.self) private var sessao  // acessado de qualquer nível

    var body: some View {
        if let usuario = sessao.usuarioLogado {
            Text("Olá, \(usuario.nome)")
        }
    }
}

// Passagem direta (sem environment) quando existe hierarquia simples:
struct ItemView: View {
    let sessao: SessaoUsuario  // sem property wrapper

    var body: some View {
        Text(sessao.usuarioLogado?.nome ?? "Sem usuário")
    }
}

// Lendo valores do sistema:
struct TemaView: View {
    @Environment(\.colorScheme) private var esquema
    @Environment(\.horizontalSizeClass) private var tamanho
    @Environment(\.locale) private var locale

    var body: some View {
        VStack {
            Text(esquema == .dark ? "Modo escuro" : "Modo claro")
            Text(tamanho == .compact ? "iPhone" : "iPad/Mac")
        }
    }
}

// Fechando um modal com dismiss:
struct FormularioModal: View {
    @Environment(\.dismiss) private var fechar

    var body: some View {
        Button("Fechar") {
            fechar()  // fecha o modal sem precisar de @Binding
        }
    }
}
